            if (!visited[v] && inDeg[v] == 0)
            {
                visited[v] = true;
                foreach (int w in adj[v]) inDeg[w]--;
                Backtrack(placed + 1);
                visited[v] = false;
                foreach (int w in adj[v]) inDeg[w]++;
            }
        }
    }
}

