pub fn topological_sort_all(arr: &[i32]) -> i32 {
    let n = arr[0] as usize;
    let m = arr[1] as usize;
    let mut adj = vec![vec![]; n];
    let mut in_deg = vec![0i32; n];
    for i in 0..m {
        let u = arr[2 + 2 * i] as usize;
        let v = arr[2 + 2 * i + 1] as usize;
        adj[u].push(v);
        in_deg[v] += 1;
    }
    let mut visited = vec![false; n];
    let mut count = 0i32;

    fn backtrack(
        placed: usize, n: usize, adj: &[Vec<usize>], in_deg: &mut [i32],
        visited: &mut [bool], count: &mut i32,
    ) {
        if placed == n { *count += 1; return; }
        for v in 0..n {
            if !visited[v] && in_deg[v] == 0 {
                visited[v] = true;
                for &w in &adj[v] { in_deg[w] -= 1; }
                backtrack(placed + 1, n, adj, in_deg, visited, count);
                visited[v] = false;
                for &w in &adj[v] { in_deg[w] += 1; }
            }
        }
    }

    backtrack(0, n, &adj, &mut in_deg, &mut visited, &mut count);
    count
}

object TopologicalSortAll {

  def topologicalSortAll(arr: Array[Int]): Int = {
    val n = arr(0); val m = arr(1)
    val adj = Array.fill(n)(scala.collection.mutable.ListBuffer[Int]())
    val inDeg = Array.fill(n)(0)
    for (i <- 0 until m) {
      val u = arr(2 + 2 * i); val v = arr(2 + 2 * i + 1)
      adj(u) += v; inDeg(v) += 1
    }
    val visited = Array.fill(n)(false)
    var count = 0

    def backtrack(placed: Int): Unit = {
      if (placed == n) { count += 1; return }
      for (v <- 0 until n) {
        if (!visited(v) && inDeg(v) == 0) {
          visited(v) = true
          for (w <- adj(v)) inDeg(w) -= 1
          backtrack(placed + 1)
          visited(v) = false
          for (w <- adj(v)) inDeg(w) += 1
        }
      }
    }

    backtrack(0)
    count
  }
}

